from flask import Flask, request, redirect, session, url_for
import xml.etree.ElementTree as ET
import base64

app = Flask(__name__)
app.secret_key = 'your_secret_key'

@app.route('/saml/consume', methods=['POST'])
def consume_saml_response():
    saml_response = request.form.get('SAMLResponse')
    if not saml_response:
        return 'No SAML Response found', 400

    # Decode the SAML Response
    decoded_response = base64.b64decode(saml_response).decode('utf-8')

    # Parse the SAML Response
    root = ET.fromstring(decoded_response)
    
    # Define the namespaces
    ns = {
        'saml': 'urn:oasis:names:tc:SAML:2.0:assertion'
    }

    # Validate the assertion
    assertion = root.find('.//saml:Assertion', ns)
    if assertion is None:
        return 'No SAML Assertion found', 400
    
    # Extract user attributes
    attributes = {}
    for attribute in assertion.findall('.//saml:Attribute', ns):
        attr_name = attribute.attrib.get('Name')
        attr_value = attribute.find('./saml:AttributeValue', ns).text
        attributes[attr_name] = attr_value

    # Create user session
    session['user'] = attributes
    return redirect(url_for('profile'))

@app.route('/profile')
def profile():
    if 'user' not in session:
        return redirect(url_for('index'))
    return f"User Profile: {session['user']}"

@app.route('/')
def index():
    return 'Welcome to the SSO Service Provider'

if __name__ == '__main__':
    app.run(debug=True)